-- Week 16 / Game 16 sheet-derived score load.
-- Run after supabase/game_score_storage.sql.

BEGIN;

DELETE FROM game_player_daily_score_results WHERE season_number = 32 AND game_number = 16 AND week_number = 16;
DELETE FROM game_team_daily_score_results WHERE season_number = 32 AND game_number = 16 AND week_number = 16;
DELETE FROM game_matchup_score_results WHERE season_number = 32 AND game_number = 16 AND week_number = 16;
DELETE FROM game_score_runs WHERE season_number = 32 AND game_number = 16 AND week_number = 16;

VALUES (32, 16, 16, 'sheet_import', 'complete', NOW(), '{"sourceFile":"XXXII Game 16.xlsx","startDate":"2026-07-13","endDate":"2026-07-19"}'::jsonb);




-- Daily lineup snapshots used by roster and lineup pages.
-- Run supabase/daily_lineups.sql before this import if the table does not exist yet.
ON CONFLICT (team_slug, lineup_date) DO UPDATE SET
  lineup = EXCLUDED.lineup,
  updated_at = NOW();

COMMIT;
